{"query":"
        query GetWalletFungibleAssets(
          $address: String,
          $page: Int,
          $offset: Int,
          $blockchainEnvironment: BlockchainEnvironment,
          $isAddressName: Boolean
        ) {
          getWalletFungibleAssets(
            address: $address,
            page: $page,
            offset: $offset,
            blockchainEnvironment: $blockchainEnvironment,
            isAddressName: $isAddressName
          ) {
            fungibleAssets {
              faAddress
            }
            pageNumber
            pageCount
            totalItems
            nextPage
            isError
            errorType
          }
        }
      ","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f","page":1,"offset":100,"blockchainEnvironment":"mainnet","isAddressName":false}}

